class CountIntervals {
    private int[] tree;
    private int n;
    private int total;

    public CountIntervals() {
        n = 2000010;
        tree = new int[n];
        total = 0;
    }

    public void add(int left, int right) {
        update(left, 1);
        update(right + 1, -1);
        total += right - left + 1;
    }

    public int count() {
        return total;
    }

    private void update(int x, int val) {
        while (x < n) {
            tree[x] += val;
            x += x & -x;
        }
    }

    private int query(int x) {
        int sum = 0;
        while (x > 0) {
            sum += tree[x];
            x -= x & -x;
        }
        return sum;
    }
}
